import { LessonData } from '../index'

const w3: Record<number, LessonData> = {
  16: {
    id: 16, worldId: 3, title: 'AI and Jobs',
    stops: [
      { tag: 'Fact', title: 'The Automation Wave', body: "AI is automating tasks faster than any previous technology in history. Not just physical labor: cognitive work too. Writing, coding, designing, analyzing, translating, diagnosing. The jobs most affected are not the ones most people expected. Physical jobs that require dexterity and judgment in unpredictable environments are harder to automate than knowledge work that follows patterns. The pattern is what AI replaces." },
      { tag: 'Example', title: "What's Already Gone", body: "Some jobs have already largely disappeared or shrunk dramatically. Travel agents. Bank tellers. Toll booth operators. Data entry clerks. Film photo developers. These didn't vanish overnight. They declined over decades as automation improved. AI is accelerating that process. The World Economic Forum estimates AI will displace 85 million jobs by 2025 while creating 97 million new ones. The net number is positive. The transition is not painless." },
      { tag: 'Example', title: "What's Being Automated Now", body: "Tasks currently being automated at scale: writing first drafts, generating code, screening job applications, answering customer service questions, producing legal documents, analyzing medical images, creating marketing content, translating languages, summarizing documents. These aren't fringe tasks: they're significant parts of what lawyers, doctors, writers, programmers, and analysts do every day." },
      { tag: 'Hot take', title: 'White Collar Jobs Are More Vulnerable Than Expected', body: "The conventional wisdom was that AI would automate blue collar work first: factory jobs, truck driving, physical labor. The reality is different. AI is currently better at pattern-based knowledge work than at physical tasks requiring dexterity and judgment in unpredictable environments. A robot that can fold laundry reliably is harder to build than a system that can write a legal brief. The disruption is hitting knowledge workers first." },
      { tag: 'Fact', title: "What AI Can't Automate", body: "Tasks requiring genuine human connection, physical presence, unpredictable judgment, and creative originality are harder to automate. Nursing. Teaching in person. Plumbing. Therapy. Electrical work. Parenting. These require being in a body, in a specific place, responding to an unpredictable human situation in real time. AI can assist with all of these. It cannot replace the human at the center of them." },
      { tag: 'Example', title: 'New Jobs AI Creates', body: "Every wave of automation creates new jobs. AI is creating demand for: prompt engineers, AI trainers, model evaluators, AI ethicists, synthetic data generators, AI policy specialists, machine learning engineers, and people who can work effectively alongside AI tools. Many of these jobs didn't exist five years ago. Many of the most important ones five years from now don't exist yet." },
      { tag: 'Scenario', title: 'The Transition Problem', body: "The economic argument for AI automation is that it creates more jobs than it destroys overall. That's probably true at the macro level. It doesn't help the 55-year-old data entry clerk in Ohio whose job disappeared and who doesn't have the resources, time, or opportunity to retrain as a machine learning engineer. The aggregate numbers can be positive and the individual experience can still be devastating. They can both be true at once." },
      { tag: 'Big idea', title: 'Productivity Without Prosperity', body: "AI can increase productivity dramatically without that productivity being distributed equally. A company that automates half its workforce and doubles its revenue has achieved real economic gains. Those gains flow to shareholders. The displaced workers are not automatically beneficiaries of the productivity they helped create. How the gains from AI automation get distributed. Through wages, taxation, retraining programs, or new social contracts: is one of the defining political questions of the next decade." },
    ],
    questions: [
      { difficulty: 'Easy', tag: 'Myth bust', stopTitle: 'The Automation Wave', question: `"AI is primarily automating physical factory jobs rather than knowledge work."`, answer: false, verdict: 'Wrong.', explanation: "AI is currently better at pattern-based knowledge work than at physical tasks requiring dexterity and judgment. Writers, programmers, analysts, and lawyers are among those most immediately affected. The disruption is hitting knowledge workers first, not last." },
      { difficulty: 'Easy', tag: 'Example', stopTitle: "What's Already Gone", question: `"Some jobs like travel agents and bank tellers have already largely declined due to automation."`, answer: true, verdict: 'Correct.', explanation: "These didn't vanish overnight. They declined over decades as automation improved. AI is accelerating that process across many more job categories. The net job creation number may be positive. The transition is not painless." },
      { difficulty: 'Easy', tag: 'Example', stopTitle: "What's Being Automated Now", question: `"AI can currently perform tasks like writing first drafts, generating code, and analyzing medical images at scale."`, answer: true, verdict: 'Correct.', explanation: "These aren't fringe capabilities: they're significant parts of what lawyers, doctors, writers, and programmers do every day. The automation of cognitive work is already happening at scale." },
      { difficulty: 'Medium', tag: 'Hot take', stopTitle: 'White Collar Jobs Are More Vulnerable Than Expected', question: `"Physical jobs requiring unpredictable judgment are currently easier to automate than pattern-based knowledge work."`, answer: false, verdict: 'Wrong.', explanation: "A robot that can fold laundry reliably is harder to build than a system that can write a legal brief. Physical tasks requiring dexterity in unpredictable environments remain harder to automate. The disruption is hitting knowledge workers first." },
      { difficulty: 'Medium', tag: 'Example', stopTitle: 'New Jobs AI Creates', question: `"AI automation creates new jobs as well as displacing existing ones."`, answer: true, verdict: 'Correct.', explanation: "Every wave of automation creates new jobs. AI is creating demand for prompt engineers, AI trainers, model evaluators, and AI policy specialists. Many of these jobs didn't exist five years ago." },
      { difficulty: 'Medium', tag: 'Scenario', stopTitle: 'The Transition Problem', question: `"A positive net job creation number at the macro level means AI automation causes no individual hardship."`, answer: false, verdict: 'Wrong.', explanation: "The aggregate numbers can be positive and the individual experience can still be devastating. The 55-year-old data entry clerk whose job disappeared doesn't benefit from the macro statistic." },
      { difficulty: 'Hard', tag: 'Big idea', stopTitle: 'Productivity Without Prosperity', question: `"Productivity gains from AI automation are automatically shared with all workers."`, answer: false, verdict: 'Wrong.', explanation: "A company that automates half its workforce and doubles its revenue has achieved real gains. Those gains flow to shareholders. The displaced workers are not automatically beneficiaries. How gains get distributed is a defining political question." },
      { difficulty: 'Hard', tag: 'Big idea', stopTitle: 'Productivity Without Prosperity', question: `"How the gains from AI automation are distributed is a political and policy question, not just a technical one."`, answer: true, verdict: 'Correct.', explanation: "The technology creates gains. What happens to them depends on political choices: wages, taxation, retraining programs, new social contracts. These are among the defining political questions of the next decade." },
    ],
  },

  17: {
    id: 17, worldId: 3, title: 'AI and Creativity',
    stops: [
      { tag: 'Fact', title: 'Machines Are Making Things', body: "AI systems are now producing images, music, writing, video, code, and design at scale. Some of it is indistinguishable from human work. Some of it is better by measurable standards. Some of it is winning awards in competitions: sometimes without the judges knowing. The question of what counts as creativity, and whether machines can have it, is no longer hypothetical. It's being answered in real time by the market, by courts, and by artists trying to figure out what their work is worth." },
      { tag: 'Example', title: 'AI Art', body: "Text-to-image systems like Midjourney and DALL-E can generate photorealistic images, paintings in any style, illustrations, and graphic design from plain English descriptions in seconds. In 2022 an AI-generated image won first place at the Colorado State Fair art competition. The artist entered it knowingly. The judges didn't know. The result sparked a debate about what art is, what competitions are for, and whether disclosure should be required." },
      { tag: 'Example', title: 'AI Music', body: "AI systems can generate original music in any genre, in the style of any artist, at any tempo, for any duration. They can clone voices with a few minutes of audio. In 2023 a fake Drake and The Weeknd song generated using AI went viral before being taken down. It had millions of streams. Labels are now building AI tools to generate music for advertising, film, and games: faster and cheaper than hiring human composers." },
      { tag: 'Example', title: 'AI Writing', body: "Large language models can write news articles, novels, screenplays, poetry, marketing copy, academic papers, and legal documents. The Writers Guild of America went on strike in 2023 partly over AI, specifically over whether studios could use AI to generate scripts or require writers to edit AI-generated content. The strike resulted in some AI protections for writers. The underlying tension between AI capabilities and human creative work remains unresolved." },
      { tag: 'Hot take', title: 'The Training Data Question', body: "Every AI creative system learned from human work. Midjourney trained on millions of images made by human artists. Language models trained on books written by human authors. The artists and authors whose work was used for training were not compensated and in most cases did not consent. Multiple lawsuits are ongoing. The question of whether training on copyrighted work constitutes infringement has not been resolved in court." },
      { tag: 'Fact', title: 'What AI Changes About Creative Work', body: "AI doesn't eliminate creative work. It changes what the work is. A graphic designer using AI generates dozens of options in minutes instead of one in hours. The skill shifts from execution to curation, direction, and judgment. A writer using AI produces more content faster. The skill shifts from drafting to editing, shaping, and deciding what's worth keeping. These are real skills. They're different skills. The market for them is different." },
      { tag: 'Scenario', title: 'The Attribution Problem', body: "When an AI generates an image, who owns it? The person who wrote the prompt? The company that built the model? The artists whose work trained the model? Courts in different countries are reaching different conclusions. The US Copyright Office has ruled that purely AI-generated work with no human authorship cannot be copyrighted. Work with significant human creative input can be. The line between those two things is being litigated in real time." },
      { tag: 'Big idea', title: 'A New Kind Of Creative Landscape', body: "Human creative history has always involved tools: brushes, cameras, synthesizers, word processors. Each new tool changed what was possible, who could create, and what counted as skill. AI is another tool in that sequence, but one that can perform many of the tasks that previously required years of training. What that means for the value of creative work, for creative education, and for what human creativity is actually for is one of the most open questions of this moment." },
    ],
    questions: [
      { difficulty: 'Easy', tag: 'Fact', stopTitle: 'Machines Are Making Things', question: `"AI systems are producing images, music, and writing that is sometimes indistinguishable from human work."`, answer: true, verdict: 'Correct.', explanation: "Some AI output is indistinguishable from human work. Some has won competitions without judges knowing. The question of whether machines can create is being answered in real time." },
      { difficulty: 'Easy', tag: 'Example', stopTitle: 'AI Art', question: `"An AI-generated image won a major art competition in 2022."`, answer: true, verdict: 'Correct.', explanation: "An AI-generated image won first place at the Colorado State Fair art competition. The artist entered it knowingly. The judges didn't know. The result sparked debate about what art is and whether disclosure should be required." },
      { difficulty: 'Easy', tag: 'Hot take', stopTitle: 'The Training Data Question', question: `"Human artists and authors were compensated when AI systems trained on their work."`, answer: false, verdict: 'Wrong.', explanation: "They were not compensated and in most cases did not consent. Multiple lawsuits are ongoing. Whether training on copyrighted work constitutes infringement has not been resolved in court." },
      { difficulty: 'Medium', tag: 'Fact', stopTitle: 'What AI Changes About Creative Work', question: `"AI tools shift the creative skill from execution toward curation, direction, and judgment."`, answer: true, verdict: 'Correct.', explanation: "A graphic designer using AI generates dozens of options in minutes. The skill shifts from execution to deciding what's worth keeping. These are real skills. They're different skills." },
      { difficulty: 'Medium', tag: 'Myth bust', stopTitle: 'What AI Changes About Creative Work', question: `"AI completely eliminates creative work."`, answer: false, verdict: 'Wrong.', explanation: "AI changes what the work is. It doesn't eliminate it. The skill shifts from execution to curation and judgment. The work isn't gone. The nature of the work changes." },
      { difficulty: 'Medium', tag: 'Scenario', stopTitle: 'The Attribution Problem', question: `"The copyright status of purely AI-generated work is clearly settled in most countries."`, answer: false, verdict: 'Wrong.', explanation: "Courts in different countries are reaching different conclusions. The US Copyright Office has ruled purely AI-generated work cannot be copyrighted, but the line is being litigated in real time." },
      { difficulty: 'Hard', tag: 'Example', stopTitle: 'AI Writing', question: `"The 2023 Writers Guild of America strike included concerns about AI-generated scripts."`, answer: true, verdict: 'Correct.', explanation: "The WGA struck partly over whether studios could use AI to generate scripts. The strike resulted in some AI protections. The underlying tension remains unresolved." },
      { difficulty: 'Hard', tag: 'Big idea', stopTitle: 'A New Kind Of Creative Landscape', question: `"AI is unique among creative tools because it can perform tasks previously requiring years of training."`, answer: true, verdict: 'Correct.', explanation: "Brushes, cameras, synthesizers each changed what was possible and who could create. AI is another tool in that sequence, but one that can perform many tasks previously requiring years of training." },
    ],
  },

  18: {
    id: 18, worldId: 3, title: 'AI and Privacy',
    stops: [
      { tag: 'Fact', title: 'You Are Being Watched', body: "AI-powered surveillance is more pervasive than most people realize. Facial recognition cameras in cities. License plate readers on roads. Behavioral tracking on every website. Voice data from smart speakers. Location data from phones. Purchase history from credit cards. These streams of data are increasingly processed by AI systems that can identify patterns, predict behavior, and make inferences that individuals never consented to share." },
      { tag: 'Example', title: 'Facial Recognition In Public Spaces', body: "China has deployed one of the most extensive facial recognition surveillance systems in the world: hundreds of millions of cameras connected to AI systems that can identify individuals in public spaces in real time. It's used for law enforcement, traffic management, and social credit scoring. Several US cities including San Francisco and Boston have banned government use of facial recognition. Others use it routinely. The technology is the same. The policy choices are different." },
      { tag: 'Example', title: 'What Your Phone Knows', body: "Your phone knows where you are at all times. It knows who you call, what you search, what you buy, what you read, how fast you walk, how well you sleep, and what your face looks like from multiple angles. This data is collected by apps, sold to data brokers, and purchased by advertisers, employers, insurance companies, and governments. Most of it is disclosed in terms of service that almost nobody reads. The data economy is built on this exchange." },
      { tag: 'Hot take', title: 'Inferred Data Is Often More Revealing Than Disclosed Data', body: "The most sensitive information AI systems have about you is often not what you told them. It's what they inferred. Your political views inferred from your browsing history. Your health conditions inferred from your purchases. Your sexual orientation inferred from your social connections. Your mental health inferred from your typing patterns. You never disclosed these things. The AI figured them out. This inference capability is what makes modern data collection qualitatively different from previous eras." },
      { tag: 'Fact', title: 'The Data Broker Industry', body: "Data brokers are companies that collect, aggregate, and sell personal data. There are thousands of them. They collect data from public records, social media, app tracking, purchase history, and other sources. They sell profiles containing hundreds of data points on hundreds of millions of individuals. Their customers include marketers, employers, insurers, landlords, and law enforcement. In the US this industry is largely unregulated. Most people have no idea it exists." },
      { tag: 'Example', title: 'Predictive Policing', body: "Several US cities have used AI systems to predict where crimes are likely to occur and deploy police accordingly. These systems use historical crime data to generate predictions. Because historical crime data reflects where police have historically focused, which reflects existing biases, the predictions often direct police to the same neighborhoods. The system reinforces the pattern it was trained on. Critics argue it's not prediction. It's automation of existing bias." },
      { tag: 'Scenario', title: 'The Aggregation Problem', body: "Any single piece of data about you is relatively harmless. Your name. Your employer. Your neighborhood. Your physical description. Your daily routine. But combine all of them and you have a profile that enables stalking, manipulation, discrimination, and harassment. AI makes aggregation cheap and fast. Data brokers do it automatically. The aggregation problem is why privacy advocates argue that data minimization, collecting less data in the first place, is the only real solution." },
      { tag: 'Big idea', title: 'Privacy As Infrastructure', body: "Privacy is often framed as a personal preference: some people care about it, others don't. A different framing: privacy is infrastructure for other rights. Without privacy, free speech is chilled: people self-censor when they know they're being watched. Without privacy, political organizing is harder: surveillance enables targeting of dissidents. Without privacy, personal development is constrained: people behave differently under observation. What AI surveillance does to privacy it does to all the things privacy enables." },
    ],
    questions: [
      { difficulty: 'Easy', tag: 'Fact', stopTitle: 'You Are Being Watched', question: `"AI-powered surveillance today includes facial recognition, behavioral tracking, and voice data from smart speakers."`, answer: true, verdict: 'Correct.', explanation: "These streams of data are increasingly processed by AI that can identify patterns, predict behavior, and make inferences individuals never consented to share." },
      { difficulty: 'Easy', tag: 'Myth bust', stopTitle: 'Facial Recognition In Public Spaces', question: `"All governments have adopted the same policy on facial recognition in public spaces."`, answer: false, verdict: 'Wrong.', explanation: "Policies differ dramatically. China has deployed extensive AI facial recognition. San Francisco and Boston have banned government use of it. The technology is the same. The policy choices are different." },
      { difficulty: 'Easy', tag: 'Fact', stopTitle: 'The Data Broker Industry', question: `"Data brokers collect and sell detailed profiles of individuals to marketers, employers, insurers, and law enforcement."`, answer: true, verdict: 'Correct.', explanation: "There are thousands of data broker companies. Their customers include marketers, employers, insurers, landlords, and law enforcement. In the US this industry is largely unregulated. Most people have no idea it exists." },
      { difficulty: 'Medium', tag: 'Hot take', stopTitle: 'Inferred Data Is Often More Revealing Than Disclosed Data', question: `"The most sensitive information AI has about you is usually what you explicitly told it."`, answer: false, verdict: 'Wrong.', explanation: "The most sensitive information is often inferred: your health from purchases, your politics from browsing, your mental health from typing patterns. Inference capability makes modern data collection qualitatively different." },
      { difficulty: 'Medium', tag: 'Example', stopTitle: 'Predictive Policing', question: `"Predictive policing algorithms can reinforce existing biases by training on historically biased crime data."`, answer: true, verdict: 'Correct.', explanation: "Because historical crime data reflects where police have historically focused, predictions often direct police to the same neighborhoods. The system reinforces the pattern it was trained on." },
      { difficulty: 'Medium', tag: 'Scenario', stopTitle: 'The Aggregation Problem', question: `"Combining individually harmless pieces of personal data can create a profile enabling stalking and harassment."`, answer: true, verdict: 'Correct.', explanation: "Name, employer, neighborhood, appearance, and daily routine are each harmless individually. Combined they enable stalking. AI makes aggregation cheap and fast." },
      { difficulty: 'Hard', tag: 'Big idea', stopTitle: 'Privacy As Infrastructure', question: `"Privacy concerns are purely a matter of personal preference with no broader social implications."`, answer: false, verdict: 'Wrong.', explanation: "Privacy is infrastructure for other rights. Without it, free speech is chilled, political organizing is harder, and personal development is constrained. What AI surveillance does to privacy it does to all the things privacy enables." },
      { difficulty: 'Hard', tag: 'Example', stopTitle: 'What Your Phone Knows', question: `"Most data collection by apps is disclosed in terms of service, but those terms are rarely read by users."`, answer: true, verdict: 'Correct.', explanation: "The data economy is built on this exchange: data for service, disclosed in documents almost nobody reads. The gap between disclosure and understanding enables large-scale data collection." },
    ],
  },

  19: {
    id: 19, worldId: 3, title: 'AI and Healthcare',
    stops: [
      { tag: 'Fact', title: 'AI Is Already In Medicine', body: "AI systems are already deployed in healthcare at scale. They read X-rays and MRIs. They screen for diabetic retinopathy. They predict sepsis risk in hospital patients. They identify suspicious lesions in colonoscopies. They predict which patients are likely to be readmitted. They help schedule surgeries and staff hospitals. The technology is not experimental. It's in clinical use in major health systems around the world." },
      { tag: 'Example', title: 'Medical Imaging', body: "AI systems for reading medical images can match or exceed radiologist performance on specific tasks in controlled studies. Google's AI detected breast cancer in mammograms with fewer false positives and false negatives than human radiologists in a 2020 study. An AI system developed by Moorfields Eye Hospital can identify over 50 eye diseases from retinal scans with accuracy comparable to expert clinicians. The performance on narrow, well-defined image classification tasks is impressive." },
      { tag: 'Example', title: 'Drug Discovery', body: "Drug development typically takes 10-15 years and costs billions of dollars. AI is compressing that timeline. DeepMind's AlphaFold solved the protein folding problem: predicting the 3D structure of proteins from their amino acid sequences: after 50 years of failure by conventional methods. This enables drug discovery at a scale previously impossible. AI systems are now identifying drug candidates, predicting drug interactions, and designing clinical trials faster than human researchers alone." },
      { tag: 'Hot take', title: 'The Access Problem', body: "AI healthcare tools are mostly being developed and deployed in wealthy countries and high-resource health systems. The diseases that kill the most people globally, malaria, tuberculosis, cholera, receive less AI research attention than diseases common in wealthy countries. The hospitals most likely to benefit from AI diagnostic tools are already the best-resourced. The potential for AI to improve global health is real. Whether that potential gets realized depends on investment and political will, not just technology." },
      { tag: 'Fact', title: 'The FDA and AI', body: "Medical AI in the US is regulated by the FDA. A system that makes clinical decisions, recommending treatment, diagnosing disease, requires FDA clearance or approval. As of 2023 the FDA had authorized over 500 AI-enabled medical devices. Most are for radiology. The regulatory framework is still being developed. Questions about how to evaluate AI systems that learn and change over time after deployment remain actively contested." },
      { tag: 'Example', title: 'Mental Health Applications', body: "AI is being applied to mental health in multiple ways. Crisis text lines use AI to prioritize conversations. Apps use AI to deliver cognitive behavioral therapy. Researchers are using AI to analyze speech patterns, text, and social media to predict depression, anxiety, and suicide risk. These applications raise particular questions about accuracy, consent, stigma, and what happens when a machine flags someone as a suicide risk." },
      { tag: 'Scenario', title: 'The Liability Question', body: "When an AI system makes a wrong medical diagnosis and a patient is harmed, who is responsible? The hospital that deployed it? The company that built it? The doctor who relied on it? The regulatory framework hasn't resolved this. Hospitals are often reluctant to deploy AI diagnostics in high-stakes settings partly because of liability uncertainty. This uncertainty is slowing deployment of systems that might actually save lives. The accountability gap has real costs in both directions." },
      { tag: 'Big idea', title: 'Medicine As A Test Case', body: "Healthcare is where AI's promise and risks are most concentrated. The potential benefits are enormous: earlier detection, faster drug discovery, more personalized treatment, lower costs, better access. The potential harms are also serious: misdiagnosis at scale, algorithmic bias in treatment decisions, privacy violations, liability gaps. How society navigates AI in medicine will shape how it navigates AI everywhere. Medicine is not just one application of AI. It's a test case for whether AI can be deployed responsibly in high-stakes domains." },
    ],
    questions: [
      { difficulty: 'Easy', tag: 'Fact', stopTitle: 'AI Is Already In Medicine', question: `"AI systems are already in clinical use in major health systems, not just in experimental settings."`, answer: true, verdict: 'Correct.', explanation: "They read X-rays, screen for eye disease, predict sepsis risk, and identify suspicious lesions. The technology is not experimental. It's in clinical use worldwide." },
      { difficulty: 'Easy', tag: 'Example', stopTitle: 'Medical Imaging', question: `"AI has matched or exceeded radiologist performance on specific medical imaging tasks in controlled studies."`, answer: true, verdict: 'Correct.', explanation: "Google's AI detected breast cancer with fewer false positives than human radiologists. Moorfields Eye Hospital's AI identifies over 50 eye diseases with expert-comparable accuracy." },
      { difficulty: 'Easy', tag: 'Hot take', stopTitle: 'The Access Problem', question: `"AI healthcare tools are being developed and deployed equally across wealthy and lower-income countries."`, answer: false, verdict: 'Wrong.', explanation: "They're mostly developed and deployed in wealthy countries and high-resource systems. Diseases killing the most people globally receive less AI research attention." },
      { difficulty: 'Medium', tag: 'Example', stopTitle: 'Drug Discovery', question: `"AlphaFold solved the protein folding problem after it had stumped conventional science for 50 years."`, answer: true, verdict: 'Correct.', explanation: "In 2020 AlphaFold predicted 3D protein structures with accuracy matching experimental methods. In 2022 it released predictions for nearly every protein known to science." },
      { difficulty: 'Medium', tag: 'Fact', stopTitle: 'The FDA and AI', question: `"Medical AI in the US can make clinical decisions without any regulatory approval."`, answer: false, verdict: 'Wrong.', explanation: "A system that makes clinical decisions requires FDA clearance or approval. As of 2023 over 500 AI-enabled medical devices had been authorized." },
      { difficulty: 'Medium', tag: 'Scenario', stopTitle: 'The Liability Question', question: `"Liability uncertainty around AI medical diagnosis is slowing deployment of potentially beneficial systems."`, answer: true, verdict: 'Correct.', explanation: "Hospitals are reluctant to deploy AI diagnostics in high-stakes settings partly because of liability uncertainty. This is slowing systems that might actually save lives." },
      { difficulty: 'Hard', tag: 'Scenario', stopTitle: 'The Liability Question', question: `"When an AI system makes a wrong medical diagnosis and a patient is harmed, liability is clearly assigned."`, answer: false, verdict: 'Wrong.', explanation: "Was it the hospital? The company that built it? The doctor who relied on it? The regulatory framework hasn't resolved this." },
      { difficulty: 'Hard', tag: 'Big idea', stopTitle: 'Medicine As A Test Case', question: `"How society navigates AI in medicine will shape how it navigates AI in other high-stakes domains."`, answer: true, verdict: 'Correct.', explanation: "Healthcare concentrates both the promise and the risks of AI. The frameworks developed for medical AI will inform approaches across law, finance, education, and government." },
    ],
  },

  20: {
    id: 20, worldId: 3, title: 'AI and Education',
    stops: [
      { tag: 'Fact', title: 'AI Has Already Changed Education', body: "ChatGPT launched in November 2022. Within weeks schools and universities around the world were rewriting their academic integrity policies. Within months some were banning it, others were requiring its use, and most were somewhere in between: trying to figure out what education is for when a machine can write the essay, solve the problem set, and pass the exam. The technology arrived faster than institutions could respond. Most are still figuring it out." },
      { tag: 'Example', title: 'What AI Can Do On Schoolwork', body: "Current AI systems can write essays across most subjects at a level that would earn passing or good grades at most educational levels. They can solve math problems, write code, answer science questions, produce historical analyses, write poetry, and pass standardized tests including the bar exam, medical licensing exams, and the SAT. AI detection tools exist but are unreliable. They produce false positives that have led to wrongful academic misconduct accusations." },
      { tag: 'Example', title: 'Personalized Learning', body: "AI tutoring systems can adapt to individual students: identifying where understanding breaks down, presenting material differently, adjusting pace, and providing targeted practice. Khan Academy's AI tutor Khanmigo can guide students through problems with Socratic questioning rather than just giving answers. Studies of AI tutoring systems show significant learning gains in some contexts. The technology for actually personalized learning at scale exists. Implementation is the hard part." },
      { tag: 'Hot take', title: 'The Credential Problem', body: "Much of formal education is about credentialing: proving you can do things. If AI can do those things, the credential proves less. A law degree that proves you can research and write legal arguments means something different when AI can research and write legal arguments. This doesn't mean education becomes worthless. It means the things education needs to prove shift toward judgment, creativity, collaboration, and skills that remain distinctively human. What schools are credentialing is changing whether they know it or not." },
      { tag: 'Fact', title: 'The Digital Divide in AI Education', body: "Access to AI tools in education is unequal. Students with personal devices and reliable internet can use AI assistants for homework help, essay feedback, and tutoring. Students without that access cannot. Schools in wealthy districts are integrating AI tools into curricula. Schools in underfunded districts often can't afford the same tools or the training to use them well. AI has the potential to democratize access to high-quality tutoring. It also has the potential to widen existing educational inequalities." },
      { tag: 'Example', title: 'What Schools Are Actually Doing', body: "Responses to AI in education vary dramatically. Some universities have added AI use clauses to their honor codes. Some professors have switched to in-class handwritten exams. Some have redesigned assignments around AI, asking students to critique AI outputs, use AI as a starting point, or document their process. Some school districts have blocked AI tools on school networks. Others are training teachers to use them. There is no consensus because the question of what education is for has no consensus answer." },
      { tag: 'Scenario', title: 'Teaching In The Age Of AI', body: "A student who uses AI to write their history essay and submits it as their own work has done something most schools currently call cheating. A student who uses AI to generate a first draft, substantially revises it, and submits the result has done something most schools have no clear policy on. A student who uses AI to check their argument for logical errors has done something most schools would call acceptable. The line between cheating and using a tool is actually unclear and different people draw it differently." },
      { tag: 'Big idea', title: 'What Education Is Actually For', body: "The disruption AI causes to education forces a clarifying question: what is education actually for? If it's for information transfer, AI changes it profoundly: machines transmit information better and faster. If it's for developing judgment, critical thinking, and the capacity to learn new things, AI is less disruptive and possibly helpful. If it's for socializing people, building relationships, and developing character, AI changes almost nothing. The answer shapes everything about how schools should respond. Most schools haven't answered it clearly." },
    ],
    questions: [
      { difficulty: 'Easy', tag: 'Example', stopTitle: 'What AI Can Do On Schoolwork', question: `"Current AI systems can write essays and pass standardized tests like the bar exam and SAT."`, answer: true, verdict: 'Correct.', explanation: "AI can write essays that earn good grades and pass professional licensing exams. AI detection tools exist but are unreliable. They produce false positives leading to wrongful misconduct accusations." },
      { difficulty: 'Easy', tag: 'Myth bust', stopTitle: 'What Schools Are Actually Doing', question: `"Schools and universities have reached a clear consensus on how to handle AI in education."`, answer: false, verdict: 'Wrong.', explanation: "Responses vary dramatically: banning AI, requiring it, redesigning assignments. There is no consensus because the underlying question of what education is for has no consensus answer." },
      { difficulty: 'Easy', tag: 'Example', stopTitle: 'Personalized Learning', question: `"AI tutoring systems can adapt to individual students and identify where understanding breaks down."`, answer: true, verdict: 'Correct.', explanation: "Systems like Khanmigo guide students through problems with Socratic questioning. Studies show significant learning gains. The technology exists. Implementation is the hard part." },
      { difficulty: 'Medium', tag: 'Hot take', stopTitle: 'The Credential Problem', question: `"AI makes educational credentials more valuable by raising the bar for what students must demonstrate."`, answer: false, verdict: 'Wrong.', explanation: "If AI can do the things credentials certify, the credential proves less. The things education needs to prove shift toward judgment, creativity, and collaboration." },
      { difficulty: 'Medium', tag: 'Fact', stopTitle: 'The Digital Divide in AI Education', question: `"Access to AI educational tools is equal across students of different economic backgrounds."`, answer: false, verdict: 'Wrong.', explanation: "Students with devices and reliable internet can use AI tutoring tools. Students without that access cannot. AI has the potential to widen existing educational inequalities." },
      { difficulty: 'Medium', tag: 'Scenario', stopTitle: 'Teaching In The Age Of AI', question: `"Using AI to check your argument for logical errors is generally considered academic misconduct."`, answer: false, verdict: 'Wrong.', explanation: "Most schools would consider this acceptable tool use. The line between cheating and using a tool is actually unclear. The space in between is where most cases fall." },
      { difficulty: 'Hard', tag: 'Big idea', stopTitle: 'What Education Is Actually For', question: `"If education is primarily about information transfer, AI disrupts it profoundly."`, answer: true, verdict: 'Correct.', explanation: "Machines transmit information better and faster. If that's what education is for, AI changes it fundamentally. If it's for developing judgment, AI is less disruptive." },
      { difficulty: 'Hard', tag: 'Example', stopTitle: 'What AI Can Do On Schoolwork', question: `"AI detection tools can reliably identify AI-generated student work without producing false positives."`, answer: false, verdict: 'Wrong.', explanation: "AI detection tools are unreliable. They produce false positives that have led to wrongful academic misconduct accusations." },
    ],
  },

  21: {
    id: 21, worldId: 3, title: 'AI and Democracy',
    stops: [
      { tag: 'Fact', title: 'AI Is Already In Elections', body: "AI tools are being used in political campaigns to generate targeted ads, write personalized fundraising emails, produce social media content, and identify persuadable voters. Deepfake videos of political figures have appeared in elections in multiple countries. AI-generated robocalls impersonating candidates have been used to suppress voter turnout. Synthetic social media accounts amplify political messages at scale. The 2024 US election was the first presidential election in which AI-generated political content was widespread." },
      { tag: 'Example', title: 'Deepfakes In Politics', body: "In January 2024, AI-generated robocalls impersonating President Biden's voice were sent to New Hampshire voters telling them not to vote in the primary. The calls used a convincing voice clone. In Slovakia, AI-generated audio of a politician discussing vote-buying went viral two days before a parliamentary election: too close to the election for fact-checkers to effectively respond. In both cases the goal was the same: use synthetic media to deceive voters." },
      { tag: 'Example', title: 'Algorithmic Amplification', body: "Social media algorithms don't create misinformation. They amplify it. Content that generates engagement spreads further. Emotionally activating content, outrage, fear, disgust, generates more engagement than calm, accurate information. This means algorithmic amplification systematically favors emotionally activating content regardless of its accuracy. A false story that makes people angry travels farther and faster than a true correction. This is not a bug in the algorithm. It's the algorithm working as designed." },
      { tag: 'Hot take', title: "The Liar's Dividend", body: "Deepfakes create a secondary effect beyond the harm of false content: they give people a reason to disbelieve true content. A politician caught on video saying something damaging can now claim it's a deepfake. A genuine photo of an atrocity can be dismissed as AI-generated. The mere existence of convincing synthetic media corrodes trust in authentic media. Researchers call this the liar's dividend: the benefit bad actors receive from the general uncertainty about what's real." },
      { tag: 'Fact', title: 'Scale And Speed', body: "The threat AI poses to democratic information isn't just about individual deepfakes. It's about scale and speed. AI can generate thousands of unique versions of a political message, each targeted to a specific individual's psychological profile, in minutes. It can flood social media with synthetic content faster than human fact-checkers can respond. It can identify and target persuadable voters with personalized disinformation at a scale no human campaign operation could achieve. Scale changes the nature of the threat." },
      { tag: 'Example', title: 'AI and Authoritarian Control', body: "AI surveillance tools have enabled new forms of political control. China's social credit system combines AI surveillance, facial recognition, and behavioral scoring to monitor and shape citizen behavior. In multiple countries AI tools sold by private companies have been used to monitor opposition politicians, journalists, and activists. The same surveillance capabilities that enable targeted advertising enable targeted political repression. The technology is the same. The application depends on who controls it." },
      { tag: 'Scenario', title: 'The Verification Problem', body: "In 2016 a false story about a pizza restaurant being used as a front for a child trafficking ring spread across social media and led to a man firing a rifle inside the restaurant. No AI was involved. It was human-created misinformation. Now imagine the same dynamic with AI-generated content that is photorealistic, personalized to each reader, and produced at scale faster than any fact-checking operation can respond. The information environment democracy depends on is under a kind of stress it wasn't designed to handle." },
      { tag: 'Big idea', title: 'Democracy Requires Shared Reality', body: "Democratic deliberation requires some shared basis in fact: some agreed-upon reality within which disagreements happen. AI doesn't just enable specific pieces of misinformation. At scale it threatens the shared informational environment that makes democratic argument possible. When enough people can't agree on what happened, democratic debate becomes tribal conflict. Whether AI-generated synthetic media destroys that shared reality, or whether society develops the tools and institutions to preserve it, is one of the central questions facing democracies right now." },
    ],
    questions: [
      { difficulty: 'Easy', tag: 'Fact', stopTitle: 'AI Is Already In Elections', question: `"AI tools are being used in political campaigns to generate targeted ads and identify persuadable voters."`, answer: true, verdict: 'Correct.', explanation: "AI generates targeted ads, personalized emails, and social media content. The 2024 US election was the first with widespread AI-generated political content." },
      { difficulty: 'Easy', tag: 'Example', stopTitle: 'Deepfakes In Politics', question: `"AI-generated robocalls impersonating a US president were used to suppress voter turnout in a 2024 primary."`, answer: true, verdict: 'Correct.', explanation: "In January 2024, AI-generated robocalls impersonating President Biden's voice told New Hampshire voters not to vote in the primary." },
      { difficulty: 'Easy', tag: 'Myth bust', stopTitle: 'Algorithmic Amplification', question: `"Social media algorithms create misinformation by generating false content."`, answer: false, verdict: 'Wrong.', explanation: "Algorithms don't create misinformation. They amplify it. Emotionally activating content generates more engagement. A false story that makes people angry travels farther than a true correction." },
      { difficulty: 'Medium', tag: 'Hot take', stopTitle: "The Liar's Dividend", question: `"Deepfakes only cause harm through the false content they directly contain."`, answer: false, verdict: 'Wrong.', explanation: "They create the liar's dividend: the existence of convincing synthetic media corrodes trust in authentic media. Bad actors benefit from general uncertainty about what's real." },
      { difficulty: 'Medium', tag: 'Fact', stopTitle: 'Scale And Speed', question: `"AI can generate thousands of personalized political messages targeting individual psychological profiles in minutes."`, answer: true, verdict: 'Correct.', explanation: "It can flood social media with synthetic content faster than fact-checkers can respond. Scale changes the nature of the threat. It's not just individual deepfakes." },
      { difficulty: 'Medium', tag: 'Example', stopTitle: 'AI and Authoritarian Control', question: `"AI surveillance capabilities that enable targeted advertising cannot be used for targeted political repression."`, answer: false, verdict: 'Wrong.', explanation: "The same capabilities serve both purposes. AI tools have been used to monitor opposition politicians, journalists, and activists in multiple countries." },
      { difficulty: 'Hard', tag: 'Big idea', stopTitle: 'Democracy Requires Shared Reality', question: `"Democratic deliberation requires some shared basis in fact: an agreed-upon reality within which disagreements happen."`, answer: true, verdict: 'Correct.', explanation: "When enough people can't agree on what happened, democratic debate becomes tribal conflict. AI at scale threatens the shared informational environment that makes democratic argument possible." },
      { difficulty: 'Hard', tag: 'Example', stopTitle: 'Deepfakes In Politics', question: `"The timing of AI-generated disinformation before an election can be strategically designed to prevent effective fact-checking."`, answer: true, verdict: 'Correct.', explanation: "In Slovakia, AI-generated audio went viral two days before a parliamentary election: too close for fact-checkers to effectively respond." },
    ],
  },

  22: {
    id: 22, worldId: 3, title: 'AI and Science',
    stops: [
      { tag: 'Fact', title: 'Science Is Being Transformed', body: "AI is accelerating scientific discovery across almost every field. Not as a replacement for scientists: as a tool that dramatically expands what scientists can do. It finds patterns in datasets too large for humans to analyze. It generates hypotheses that humans hadn't considered. It designs experiments, analyzes results, and suggests follow-up questions. The pace of scientific discovery in fields where AI is deeply integrated: genomics, drug discovery, materials science, climate modeling: is measurably faster." },
      { tag: 'Example', title: 'Protein Folding', body: "For 50 years, predicting how a protein folds from its amino acid sequence was one of biology's hardest unsolved problems. In 2020 DeepMind's AlphaFold solved it. It predicted the 3D structure of proteins with accuracy that matched experimental methods. In 2022 AlphaFold released predictions for nearly every protein known to science: over 200 million structures. This database is accelerating drug discovery, vaccine development, and our understanding of disease in ways that will take decades to fully realize." },
      { tag: 'Example', title: 'Climate Modeling', body: "Climate models are some of the most computationally intensive simulations in science. AI is improving them in multiple ways: identifying patterns in climate data, improving the resolution of regional predictions, and accelerating the processing of satellite data. Google DeepMind's weather prediction model GraphCast outperformed traditional numerical weather forecasting on most metrics in 2023. AI isn't replacing climate science. It's giving climate scientists tools that were previously out of reach." },
      { tag: 'Hot take', title: 'The Reproducibility Question', body: "Science depends on reproducibility: results that can be verified by others. When an AI system discovers something by finding patterns in a massive dataset, reproducing that discovery requires access to the same dataset and the same model. If those are proprietary, which they often are, the discovery can't be independently verified in the traditional sense. AI is accelerating discovery and simultaneously creating new challenges for the verification processes that make scientific knowledge trustworthy." },
      { tag: 'Fact', title: 'AI In Genomics', body: "The human genome has 3 billion base pairs. Analyzing genomic data at scale was previously impossible: too much data, too many variables. AI has changed that. AI systems can now identify genetic variants associated with diseases, predict which patients will respond to which treatments, and design gene therapies targeted to individual genetic profiles. Personalized medicine, treatment tailored to your specific biology, is becoming real rather than theoretical, partly because of AI's ability to find patterns in genomic data." },
      { tag: 'Example', title: 'Drug Discovery', body: "Traditional drug discovery is expensive and slow: a 10-15 year process with high failure rates. AI is changing it at every stage. Identifying potential drug molecules. Predicting how they'll interact with target proteins. Predicting toxicity before clinical trials. Designing clinical trials to be more efficient. In 2020 Insilico Medicine used AI to identify a novel drug candidate for pulmonary fibrosis in 46 days: a process that typically takes years. The first AI-designed drug entered clinical trials in 2023." },
      { tag: 'Scenario', title: 'The Dual Use Problem', body: "AI tools that accelerate beneficial science also accelerate potentially harmful science. A model that helps design therapeutic proteins can also help design harmful ones. A model that identifies genetic vulnerabilities for treatment can also identify genetic vulnerabilities for harm. Biosecurity researchers call this the dual use problem: the same capabilities serve both beneficial and catastrophic ends. The biology research community is actively debating how to govern AI tools in life sciences research. There are no easy answers." },
      { tag: 'Big idea', title: 'The Pace Of Discovery', body: "Scientific progress has historically been constrained by how fast humans can run experiments, analyze data, and generate hypotheses. AI removes or reduces several of those constraints simultaneously. The pace of discovery in AI-assisted fields is accelerating in ways that outrun existing regulatory, ethical, and institutional frameworks. We may be discovering things. In genomics, materials science, neuroscience, climate science: faster than we can think through what to do with them. Whether that's a problem depends on what we discover." },
    ],
    questions: [
      { difficulty: 'Easy', tag: 'Fact', stopTitle: 'Science Is Being Transformed', question: `"AI is accelerating scientific discovery by replacing scientists with automated systems."`, answer: false, verdict: 'Wrong.', explanation: "AI accelerates discovery as a tool, not a replacement. Scientists still design what matters and interpret what it means." },
      { difficulty: 'Easy', tag: 'Example', stopTitle: 'Protein Folding', question: `"AlphaFold solved the protein folding problem that had stumped biologists for 50 years."`, answer: true, verdict: 'Correct.', explanation: "In 2020 AlphaFold predicted 3D protein structures with accuracy matching experimental methods. In 2022 it released predictions for nearly every known protein." },
      { difficulty: 'Easy', tag: 'Fact', stopTitle: 'AI In Genomics', question: `"AI has made personalized medicine, treatment tailored to individual genetic profiles, more practically achievable."`, answer: true, verdict: 'Correct.', explanation: "The human genome has 3 billion base pairs. AI can now identify genetic variants, predict treatment responses, and design targeted gene therapies." },
      { difficulty: 'Medium', tag: 'Hot take', stopTitle: 'The Reproducibility Question', question: `"AI-discovered scientific results are always reproducible because the methods are transparent."`, answer: false, verdict: 'Wrong.', explanation: "When an AI finds patterns in a massive proprietary dataset using a proprietary model, traditional verification may be impossible." },
      { difficulty: 'Medium', tag: 'Example', stopTitle: 'Drug Discovery', question: `"AI has compressed drug discovery timelines that traditionally took 10-15 years."`, answer: true, verdict: 'Correct.', explanation: "In 2020 Insilico Medicine identified a novel drug candidate in 46 days. The first AI-designed drug entered clinical trials in 2023." },
      { difficulty: 'Medium', tag: 'Scenario', stopTitle: 'The Dual Use Problem', question: `"AI tools that accelerate beneficial science cannot be used for harmful scientific purposes."`, answer: false, verdict: 'Wrong.', explanation: "This is the dual use problem. The same capabilities serve both beneficial and catastrophic ends." },
      { difficulty: 'Hard', tag: 'Example', stopTitle: 'Climate Modeling', question: `"AI weather prediction models have outperformed traditional numerical weather forecasting on multiple metrics."`, answer: true, verdict: 'Correct.', explanation: "Google DeepMind's GraphCast outperformed traditional numerical weather forecasting on most metrics in 2023." },
      { difficulty: 'Hard', tag: 'Big idea', stopTitle: 'The Pace Of Discovery', question: `"The accelerating pace of AI-assisted scientific discovery may outrun existing regulatory and ethical frameworks."`, answer: true, verdict: 'Correct.', explanation: "We may be discovering things faster than we can think through what to do with them. AI creates new governance challenges." },
    ],
  },

  23: {
    id: 23, worldId: 3, title: 'AI and Daily Life',
    stops: [
      { tag: 'Fact', title: 'AI Is Ordinary Now', body: "Five years ago using AI felt like using technology. Now it's invisible. The navigation app rerouting around traffic. The spam filter that catches 99% of junk. The autocorrect that fixes your typos. The face unlock on your phone. The fraud detection that flagged that weird charge on your card before you noticed it. None of these feel like AI anymore. They just feel like things that work. AI has become infrastructure. You notice it when it fails, not when it functions." },
      { tag: 'Example', title: 'Shopping', body: "AI shapes almost every aspect of online shopping. What products appear when you search. What gets recommended. What price you're shown: dynamic pricing means the same item can cost different amounts to different buyers at the same time. What reviews are shown first. Whether your return is approved automatically. What ads follow you around the internet after you browse a product. The experience of shopping online is almost entirely mediated by AI systems optimizing for conversion." },
      { tag: 'Example', title: 'Transportation', body: "AI is embedded in transportation at every scale. Traffic light timing in cities is increasingly AI-optimized. Navigation apps use real-time AI to route around congestion. Ride-sharing prices are set by AI demand models. Commercial airlines use AI for fuel optimization, maintenance prediction, and weather routing. The first fully autonomous vehicle robotaxis are operating commercially in San Francisco and Phoenix. Self-driving trucking is being piloted on major highways. The road system is becoming an AI-managed network." },
      { tag: 'Hot take', title: 'The Convenience Tradeoff', body: "AI convenience comes with a cost that's easy to miss because it's distributed and invisible. Every time AI makes something easier it typically does so by collecting data about you, optimizing for someone else's objective, and reducing your need to develop a skill or make a judgment. The navigation app that always tells you where to go means you never develop spatial reasoning. The recommendation algorithm that always finds your next show means you never develop taste through exploration. These tradeoffs are real even when the convenience is genuine." },
      { tag: 'Fact', title: 'AI and Mental Health', body: "Research is beginning to document relationships between heavy use of AI-mediated platforms and mental health outcomes, particularly in young people. The relationship is complex and contested: correlation doesn't establish causation and effects vary by type of use. What is clear is that AI-powered social media platforms are designed to maximize engagement, that maximizing engagement often means maximizing emotional arousal, and that chronic high emotional arousal has documented mental health effects. The research is ongoing. The deployment is already at scale." },
      { tag: 'Example', title: 'Smart Homes', body: "Smart home devices, thermostats, doorbells, speakers, lights, locks, are AI systems that learn your patterns, respond to your voice, and collect data about your home environment continuously. They're also potential surveillance devices. Smart TVs track what you watch. Smart speakers record ambient audio. Smart doorbells upload video of everyone who approaches your home. This data is stored by the companies that make these devices and subject to their privacy policies and to law enforcement requests." },
      { tag: 'Scenario', title: 'Ambient AI', body: "The next generation of AI interfaces isn't a chat window. It's ambient. Always present, always listening, always available, woven into glasses, earbuds, watches, and home environments. Several major tech companies have products in development or early release that aim for this model. The vision is an AI that knows your schedule, your preferences, your relationships, your location, and your immediate context at all times and provides assistance proactively without being asked. The convenience is real. So is the data collection it requires." },
      { tag: 'Big idea', title: 'AI As Environment', body: "We tend to think of AI as a tool we use. A more accurate description of where we're heading is AI as environment: something we move through rather than something we pick up and put down. The physical environment around us is increasingly instrumented, monitored, and optimized by AI systems. The information environment we inhabit is increasingly generated, curated, and personalized by AI. The social environment we navigate is increasingly mediated by AI-powered platforms. When AI is the environment rather than the tool, the question of how to relate to it changes fundamentally." },
    ],
    questions: [
      { difficulty: 'Easy', tag: 'Fact', stopTitle: 'AI Is Ordinary Now', question: `"AI has become invisible infrastructure in daily life: you notice it when it fails, not when it works."`, answer: true, verdict: 'Correct.', explanation: "Navigation, spam filters, autocorrect, face unlock, fraud detection: none of these feel like AI anymore. AI has become infrastructure." },
      { difficulty: 'Easy', tag: 'Example', stopTitle: 'Shopping', question: `"Dynamic pricing means the same product always costs the same amount for different buyers online."`, answer: false, verdict: 'Wrong.', explanation: "Dynamic pricing means the same item can cost different amounts to different buyers at the same time based on demand, history, and user profiles." },
      { difficulty: 'Easy', tag: 'Example', stopTitle: 'Smart Homes', question: `"Smart home devices can collect and store data that is subject to law enforcement requests."`, answer: true, verdict: 'Correct.', explanation: "Smart TVs track what you watch. Smart speakers record ambient audio. This data is stored by the companies and subject to law enforcement requests." },
      { difficulty: 'Medium', tag: 'Hot take', stopTitle: 'The Convenience Tradeoff', question: `"The cost of AI convenience is distributed and invisible, making it easy to miss."`, answer: true, verdict: 'Correct.', explanation: "Every time AI makes something easier it collects data, optimizes for someone else's objective, and reduces your need to develop a skill. These tradeoffs are real even when the convenience is genuine." },
      { difficulty: 'Medium', tag: 'Fact', stopTitle: 'AI and Mental Health', question: `"The relationship between AI-mediated platform use and mental health outcomes is fully settled by research."`, answer: false, verdict: 'Wrong.', explanation: "The relationship is complex and contested. The research is ongoing. The deployment is already at scale." },
      { difficulty: 'Medium', tag: 'Scenario', stopTitle: 'Ambient AI', question: `"Ambient AI, always present and woven into daily environments, requires significant ongoing data collection."`, answer: true, verdict: 'Correct.', explanation: "An AI that knows your schedule, preferences, relationships, and context at all times must collect that data continuously." },
      { difficulty: 'Hard', tag: 'Big idea', stopTitle: 'AI As Environment', question: `"Thinking of AI as a tool we pick up and put down accurately describes how AI is integrating into daily life."`, answer: false, verdict: 'Wrong.', explanation: "A more accurate description is AI as environment: something we move through. When AI is the environment rather than the tool, the question of how to relate to it changes fundamentally." },
      { difficulty: 'Hard', tag: 'Example', stopTitle: 'Transportation', question: `"Fully autonomous vehicle robotaxis are operating commercially in some US cities."`, answer: true, verdict: 'Correct.', explanation: "The first fully autonomous vehicle robotaxis are operating commercially in San Francisco and Phoenix. The road system is becoming an AI-managed network." },
    ],
  },
}

